    client_event_id text,
    source_event_id text,
    title text,
    date date,
    time text,
    event_type text,
    status text,
    season text,
    picture_day_info text,
    canonical_school text,
    photographers text[],
    assistants text[],
    no_assistant boolean,
    irm numeric,
    rain_info text,
    history text,
    source text,
    active boolean
  )
)
insert into public.events (
  client_event_id,
  source_event_id,
  title,
  date,
  time,
  event_type,
  status,
  season,
  picture_day_info,
  canonical_school,
  photographers,
  assistants,
  no_assistant,
  irm,
  rain_info,
  history,
  source,
  active
)
select
  incoming.client_event_id,
  incoming.source_event_id,
  incoming.title,
  incoming.date,
  incoming.time,
  incoming.event_type,
  incoming.status,
  incoming.season,
  incoming.picture_day_info,
  incoming.canonical_school,
  coalesce(incoming.photographers, '{}'::text[]),
  coalesce(incoming.assistants, '{}'::text[]),
  coalesce(incoming.no_assistant, false),
  incoming.irm,
  incoming.rain_info,
  incoming.history,
  incoming.source,
  coalesce(incoming.active, true)
from incoming
where not exists (
  select 1 from public.events existing
  where existing.source = incoming.source
    and existing.source_event_id = incoming.source_event_id
);
